rules.pseudocode:
for each action a:
  if a == 'eat' and food_here:
    V_GD[s][a] = p_hat.get((s,a,'food'), 0.5) * r_D_food + (1 - p_hat.get((s,a,'food'), 0.5)) * r_D_nofood
  elif a in ['move_up','move_down','move_left','move_right']:
    s_next = clamp_to_grid(apply_move(s, a))
    # For GD movement values, estimate future value from habit strengths at destination
    V_GD[s][a] = c_step + gamma * max(H.get((s_next, a2), 0.0) for a2 in actions) * r_D_food
  else:
    V_GD[s][a] = c_step

if gd_was_used:
  C = clip(C + rho * (C_max - C) - xi, 0.0, C_max)
else:
  C = clip(C + rho * (C_max - C), 0.0, C_max)

if C >= theta:
  p_GD = C
else:
  p_GD = 0.0

u = random_uniform(0, 1)
if u < p_GD:
  use_gd = True
  for a in actions:
    U[a] = V_GD[s][a]
else:
  use_gd = False
  for a in actions:
    U[a] = H.get((s, a), 0.0)

p_hat[(s, action, o_obs)] = p_hat.get((s, action, o_obs), 0.5) + alpha_T * (1.0 - p_hat.get((s, action, o_obs), 0.5))
for o != o_obs:
  p_hat[(s, action, o)] = p_hat.get((s, action, o), 0.5) + alpha_T * (0.0 - p_hat.get((s, action, o), 0.5))
